patch:
--- a/comparator.v
+++ b/comparator.v
@@ -1,10 +1,10 @@
 module magnitude_comparator_32(
     input [31:0] x, y, offset,
     output reg greater, equal, less
 );
-    always @(x)
+    always @(*)
         if (x + offset > y)
             {greater, equal, less} = 3'b100;
         else if (x + offset == y)
             {greater, equal, less} = 3'b010;

before_code:
module magnitude_comparator_32(
    input [31:0] x, y, offset,
    output reg greater, equal, less
);
    always @(x)
        if (x + offset > y)
            {greater, equal, less} = 3'b100;
        else if (x + offset == y)
            {greater, equal, less} = 3'b010;
        else
            {greater, equal, less} = 3'b001;
endmodule

after_code:
module magnitude_comparator_32(
    input [31:0] x, y, offset,
    output reg greater, equal, less
);
    always @(*)
        if (x + offset > y)
            {greater, equal, less} = 3'b100;
        else if (x + offset == y)
            {greater, equal, less} = 3'b010;
        else
            {greater, equal, less} = 3'b001;
endmodule
